-- 每日运势详情表
CREATE TABLE IF NOT EXISTS `tb_daily_fortune_detail` (
  `id` BIGINT NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `fortune_date` DATE NOT NULL COMMENT '运势日期',
  `love_score` INT DEFAULT 0 COMMENT '爱情运势分数(0-100)',
  `love_analysis` TEXT COMMENT '爱情运势详细分析',
  `career_score` INT DEFAULT 0 COMMENT '事业运势分数(0-100)',
  `career_analysis` TEXT COMMENT '事业运势详细分析',
  `wealth_score` INT DEFAULT 0 COMMENT '财富运势分数(0-100)',
  `wealth_analysis` TEXT COMMENT '财富运势详细分析',
  `health_score` INT DEFAULT 0 COMMENT '健康运势分数(0-100)',
  `health_analysis` TEXT COMMENT '健康运势详细分析',
  `study_score` INT DEFAULT 0 COMMENT '学习运势分数(0-100)',
  `study_analysis` TEXT COMMENT '学习运势详细分析',
  `relationship_score` INT DEFAULT 0 COMMENT '人际运势分数(0-100)',
  `relationship_analysis` TEXT COMMENT '人际运势详细分析',
  `lucky_color` VARCHAR(50) COMMENT '幸运颜色',
  `lucky_number` VARCHAR(20) COMMENT '幸运数字',
  `lucky_direction` VARCHAR(50) COMMENT '幸运方位',
  `lucky_time` VARCHAR(50) COMMENT '幸运时间',
  `suitable_actions` TEXT COMMENT '今日宜做事项(JSON数组)',
  `unsuitable_actions` TEXT COMMENT '今日忌做事项(JSON数组)',
  `overall_advice` TEXT COMMENT '综合运势建议',
  `keywords` VARCHAR(200) COMMENT '今日关键词',
  `create_time` DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_fortune_date` (`fortune_date`),
  KEY `idx_fortune_date` (`fortune_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='每日运势详情表';

